.sandbox-container {
  display: flex;
  flex-direction: row;
  justify-content: center;
  align-items: center;
  gap: 20px;
  background-color: #1e293b;
  padding: 40px;
  border-radius: 24px;
  border: 1px solid #334155;
  grid-template-columns: repeat(2, 1fr);
}

.sandbox-item {
  display: inline-flex;
  width: 120px;
  height: 120px;
  border-radius: 12px;
  color: #ffffff;
  font-weight: 700;
  font-size: 1.1rem;
  justify-content: center;
  align-items: center;
  box-shadow: 0 10px 20px rgba(0,0,0,0.3);
}

.item-1 {
  background: linear-gradient(135deg, #ff007f, #ff7f00);
}

.item-2 {
  background: linear-gradient(135deg, #00f3ff, #007fff);
}

.item-3 {
  background: linear-gradient(135deg, #00ff7f, #7fff00);
}

.item-4 {
  background: linear-gradient(135deg, #7f00ff, #ff00ff);
}

blocks.code:
/* Targets EVERY paragraph on the page */
p {
  font-size: 1rem;
  line-height: 1.6;
  color: #e0e0e0;
}

/* Targets EVERY anchor tag */
a {
  color: cyan;
  text-decoration: none;
}

/* A reusable button class */
.btn {
  padding: 0.75rem 1.5rem;
  border: none;
  border-radius: 6px;
  cursor: pointer;
  font-weight: 600;
}

/* Modifier classes */
.btn-primary { background: cyan; color: #000; }
.btn-danger  { background: #ff3333; color: #fff; }

#site-header {
  position: sticky;
  top: 0;
  z-index: 1000;
  background: #0a0a0a;
}

/* Any <a> inside .navbar, no matter how deep */
.navbar a {
  color: white;
  text-decoration: none;
}

/* Only direct <li> children of .menu */
.menu > li {
  display: inline-block;
  margin-right: 1rem;
}

/* Style the paragraph right after an h2 */
h2 + p {
  font-size: 1.1rem;
  color: #aaa;
}

/* Style ALL paragraphs after an h2 */
h2 ~ p {
  margin-left: 1rem;
}

/* Exact match */
input[type="email"] { border-color: cyan; }

/* Starts with */
a[href^="https"] { color: green; }

/* Ends with */
a[href$=".pdf"] { color: red; }

/* Contains */
a[href*="github"] { font-weight: bold; }

button {
  background: #1a1a1a;
  border: 1px solid cyan;
  color: cyan;
  transition: all 0.3s ease;
}

button:hover {
  background: cyan;
  color: #000;
  box-shadow: 0 0 15px rgba(0, 243, 255, 0.5);
}

button:active {
  transform: scale(0.97);
}

input:focus {
  outline: none;
  border-color: var(--neon-green);
  box-shadow: 0 0 8px rgba(0, 255, 65, 0.3);
}

/* Zebra-stripe a table */
tr:nth-child(even) {
  background: rgba(255, 255, 255, 0.03);
}

/* Style only the first paragraph */
p:first-of-type {
  font-size: 1.2rem;
  font-weight: 600;
}

/* Remove bottom margin from last item */
.card:last-child {
  margin-bottom: 0;
}

.badge::before {
  content: '⚡';
  margin-right: 0.5rem;
}

.quote::after {
  content: '';
  display: block;
  width: 60px;
  height: 3px;
  background: var(--neon-cyan);
  margin-top: 1rem;
}

p::first-line {
  font-weight: bold;
  color: white;
}

/* Specificity: 0,0,1,1 = 11 */
ul.nav li { color: white; }

/* Specificity: 0,1,0,1 = 101 — WINS */
#main-menu li { color: cyan; }

.btn { color: red; }
.btn { color: blue; }
/* Result: blue wins — it comes last */

.box {
  box-sizing: content-box; /* Default */
  width: 200px;
  padding: 20px;
  border: 5px solid white;
}
/* Total rendered width = 200 + 40 + 10 = 250px! */

*, *::before, *::after {
  box-sizing: border-box;
}

