blocks.code:
body {
  /* Custom → System → Generic */
  font-family:
    'Inter',
    system-ui,
    -apple-system,
    'Segoe UI',
    sans-serif;
}

body {
  line-height: 1.6;       /* Generous for body text */
  letter-spacing: -0.01em; /* Slightly tighter for modern feel */
}

h1, h2, h3 {
  line-height: 1.2;       /* Tighter for headings */
  letter-spacing: -0.02em;
}

.tag {
  position: relative;
  top: -5px;   /* Nudges UP by 5px visually */
  left: 10px;  /* Nudges RIGHT by 10px */
  /* Other elements still behave as if .tag hasn't moved */
}

.card {
  position: relative; /* Becomes the anchor */
}

.card .badge {
  position: absolute;
  top: -10px;
  right: -10px;
  /* Floats at the top-right corner of .card */
}

/* Always visible at the top */
.navbar {
  position: fixed;
  top: 0;
  width: 100%;
  z-index: 1000;
}

/* Sticks when scrolled to */
.section-title {
  position: sticky;
  top: 0;
  background: #0a0a0a;
}

