.flex-parent {
  display: flex;
  flex-direction: row;       /* or column */
  justify-content: center;   /* center, space-between, space-around, flex-start, flex-end */
  align-items: center;       /* center, stretch, flex-start, flex-end, baseline */
  flex-wrap: wrap;           /* Allow items to wrap to next line */
  gap: 1rem;                 /* Space between items */
}

.flex-child {
  flex-grow: 1;    /* How much the item should grow */
  flex-shrink: 0;  /* How much the item should shrink */
  flex-basis: 200px; /* The initial size before growing/shrinking */

  /* Shorthand: grow shrink basis */
  flex: 1 0 200px;

  /* Override alignment for just this item */
  align-self: flex-end;
}

